%[text] # Lab 1 System Identification Prototype
%[text] This script demonstrates how to process the records from the step response experiments to identify the linear model parameters.
%[text] ## Load the Data
%[text] We start with the raw data.  In this case the data is contains just the fields we need from the larger raw data fiel.
clear;
load("./step_resp_example.BIN.proc.mat");
%%
%[text] ## Create a single step response
%[text] To make this a bit general, we'll select just one set of input and output and give it general names so that we can more easily reuse the code.
in_t = dd.RCOU_timestamp;
in_y = dd.RCOU_C3;
out_t = dd.GPS_timestamp;
out_y = dd.GPS_Spd;
%[text] Now plot
figure(1); %[output:23e35f7d]
clf; %[output:23e35f7d]
ax1=subplot(211); %[output:23e35f7d]
plot(in_t, in_y, 'b-') %[output:23e35f7d]
ylabel('Input (PWM)'); %[output:23e35f7d]
title('Step Response'); %[output:23e35f7d]
grid on; %[output:23e35f7d]
ax2 = subplot(212); %[output:23e35f7d]
plot(out_t, out_y, 'r-'); %[output:23e35f7d]
ylabel("Output (m/s)") %[output:23e35f7d]
xlabel('Time (s)'); %[output:23e35f7d]
grid on; %[output:23e35f7d]
linkaxes([ax1, ax2], 'x');  %[output:23e35f7d]
%%
%[text] ## Modify the timestamps
%[text] The raw timestamps are [unix times](https://www.unixtimestamp.com/) in elapsed seconds since 1 January 1970 UTC.  We will convert these by
%[text] 1. Assume that the experiment was run on a single day (UTC)
%[text] 2. Find the day and add this to the title of the figure as a date text string
%[text] 3. Convert the timestamps to a new timestamp in elapsed seconds since the start of the current day.
%[text] 4. Replot both curves with the new timestamps. \
% 1-2. Find the calendar date from the first timestamp
t_day_start = dateshift(datetime(in_t(1), 'ConvertFrom', 'posixtime', 'TimeZone', 'UTC'), 'start', 'day');
date_str = string(t_day_start, 'yyyy-MM-dd');

% 3. Convert timestamps to elapsed seconds since start of day
t_day_start_unix = posixtime(t_day_start);
in_t_day  = in_t  - t_day_start_unix;
out_t_day = out_t - t_day_start_unix;

% 4. Replot with new timestamps
figure(1);
clf; %[output:50c8ab60]
ax1 = subplot(211); %[output:50c8ab60]
plot(in_t_day, in_y, 'b-') %[output:50c8ab60]
ylabel('Input (PWM)'); %[output:50c8ab60]
title(sprintf('Step Response — %s (UTC)', date_str)); %[output:50c8ab60]
grid on; %[output:50c8ab60]
ax2 = subplot(212); %[output:50c8ab60]
plot(out_t_day, out_y, 'r-'); %[output:50c8ab60]
ylabel('Output (m/s)'); %[output:50c8ab60]
xlabel('Elapsed time since midnight UTC (s)'); %[output:50c8ab60]
grid on; %[output:50c8ab60]
linkaxes([ax1, ax2], 'x'); %[output:50c8ab60]
%%
%[text] ## Isolate a single step response
%[text] Using the graph, select start and stop times to isolate a single step response we can use for system identification.  This process is manual and uses MATLAB's figure tools.
%[text] One way to do this is...
%[text] - Open the figure in a separate window
%[text] - Use the zoom and data tips graphical tools to select three points: start, time zero (when the step input begins) and end. \
tstart = 80121;
t0 = 80122.9;
tend = 80135.2;
%[text] Annotate the original plot to double check by adding markers to both timeseries plots to show the three points.
figure(1);
axes(ax1); hold on; %[output:94a8f197]
xline(tstart, 'g--', 'tstart', 'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
xline(t0,     'k-',  't_0',    'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
xline(tend,   'r--', 'tend',   'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
axes(ax2); hold on; %[output:94a8f197]
xline(tstart, 'g--', 'tstart', 'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
xline(t0,     'k-',  't_0',    'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
xline(tend,   'r--', 'tend',   'LabelVerticalAlignment', 'bottom'); %[output:94a8f197]
%%
%[text] ## Plot the isolated step response
%[text] Shift time so $t=0$ corresponds to `t0` (when the step begins), then extract the window and replot.
in_mask  = in_t_day  >= tstart & in_t_day  <= tend;
out_mask = out_t_day >= tstart & out_t_day <= tend;

in_t_step  = in_t_day(in_mask)  - t0;
in_y_step  = in_y(in_mask);
out_t_step = out_t_day(out_mask) - t0;
out_y_step = out_y(out_mask);

figure(2); clf; %[output:05d3af06]
ax3 = subplot(211); %[output:05d3af06]
plot(in_t_step, in_y_step, 'b-'); %[output:05d3af06]
ylabel('Input (PWM)'); %[output:05d3af06]
title(sprintf('Isolated Step Response — %s (UTC)', date_str)); %[output:05d3af06]
grid on; %[output:05d3af06]
ax4 = subplot(212); %[output:05d3af06]
plot(out_t_step, out_y_step, 'r-', "DisplayName","Exp"); %[output:05d3af06]
ylabel('Output (m/s)'); %[output:05d3af06]
xlabel('Time relative to step (s)'); %[output:05d3af06]
grid on; %[output:05d3af06]
linkaxes([ax3, ax4], 'x'); %[output:05d3af06]
%%
%[text] ## Scale the input to percentage
%[text] The input is in units of PWM, but because the ArduPilot works in units of percent effort, we need to scale the input based on the configured PWM limits from the ArduPilot configuration parameters.  For throttle (RC channel 3) and steering (RC channel 1) the values are .params fiel are
%[text] ```
%[text] RC3_MAX,1910
%[text] RC3_MIN,1109
%[text] RC1_MAX,1900
%[text] RC1_MIN,1100
%[text] ```
in0 = 1500;
inmax = 1910;
inmin = 1109;
%[text] Convert the PWM input to normalized effort (±1) and update the isolated step response plot.
in_y_pct = (in_y_step - inmin) / (inmax - inmin);

figure(2);
axes(ax3); %[output:7ff0d714]
cla; %[output:3d8fe21e]
plot(in_t_step, in_y_pct, 'b-'); %[output:3d8fe21e]
ylabel('Input (norm., ±1)'); %[output:3d8fe21e]
grid on %[output:3d8fe21e]
%%
%[text] ## Estimate first-order response model parameters.
%[text] The generic first-order model is
%[text] $G(s) = \\frac{K\_{DC}}{\\tau \\, s +1}$
%[text] By inspecting the graphs we can come up with a rough estimate of the model paramameters.
%[text] From the steady state values we can estimate the DC gain.
in_ss = 0.58;  % Fraction 
out_ss = 1.25;  % m/s
Kdc_est = out_ss/in_ss %[output:8abe6804]
%[text] From the output, we can estimate the time constant
tau_est = 0.75; %s
%[text] And overlay the response from our estimated transfer function model.  The step response, in the time domain, is
%[text] $y(t) = A\_{\\text{step}} \\, K\_{DC} \\, \\left( 1- e^{-t/\\tau}\\right)$
%[text] where $A\_{\\text{step}}$ is the amplitude of the step input.
Astep = in_ss;
%[text] We want to just have the input times greater than zero.
tmask = out_t_step  >= 0;
tt = out_t_step(tmask);
%[text] Now generate the estimated response
yy_est = Astep * Kdc_est * (1 - exp(-tt/tau_est));
%[text] And overlay
figure(2);
axes(ax4); %[output:7b8a353a]
hold on %[output:7b8a353a]
plot(tt,yy_est,'g:',"DisplayName","Intial Est") %[output:7b8a353a]
legend("Location","southeast") %[output:7b8a353a]
%%
%[text] ## Refine the model paramters with a curve fit
%[text] We'll use the lsqcurvefit solver from the Optimization Toolbox (install if needed).
%[text] Write a function that generates the timeseries for the step input.
function y = first_order_step(params, t, Astep)
    Kdc = params(1);
    tau = params(2);
    y = Astep * Kdc * (1 - exp(-t / tau));
end
%[text] Initial guess at the params vector
params0 = [Kdc_est, tau_est];
%[text] Trim the experiment data for jsut positive values
tmask = out_t_step  >= 0;
tt = out_t_step(tmask);
yy = out_y_step(tmask);
%[text] Call the solver using an anonymous function to pass the Astep variable.
params_fit = lsqcurvefit(... %[output:group:079f0667] %[output:7f095809]
    @(p,t) first_order_step(p, t, Astep), ... %[output:7f095809]
    params0, tt, yy); %[output:group:079f0667] %[output:7f095809]
K_fit = params_fit(1) %[output:84b4bb6f]
tau_fit = params_fit(2) %[output:32f2b59a]
%[text] Overlay the new model
y_fit = first_order_step([K_fit, tau_fit], tt, Astep);
figure(2);
axes(ax4); %[output:549b1c8b]
hold on %[output:549b1c8b]
plot(tt,y_fit,'k--',"DisplayName","Fit") %[output:549b1c8b]
legend("Location","southeast") %[output:549b1c8b]
%[text] Now we have a model with parametes chosen so that the time response approximates the experiment data.
%[text] $G^\*(s) = \\frac{ \\text{K\\\_fit} } { \\text{tau\\\_fit  \\,  s + 1}\n$

